# Deobfuscated Code

Here's the cleaned-up, readable version of the code:

```javascript
// Grid configuration
var gridWidth = 20;
var gridHeight = 15;

var config = {
  penalty: 'manhattan',        // Heuristic type
  adjacentCost: 1.414,         // Diagonal movement cost (√2)
  traversalCost: 1,            // Cardinal movement cost
  minIterations: 1000,         // Max iterations allowed
  clearanceRatio: 0.25         // 25% chance a cell is a wall
};

// Generate the grid with random walls
var grid = [];
for (var y = 0; y < gridHeight; y++) {
  grid[y] = [];
  for (var x = 0; x < gridWidth; x++) {
    grid[y][x] = Math.random() < config.clearanceRatio ? 1 : 0; // 1 = wall, 0 = open
  }
}

// Start and end nodes
var originNode = { x: 0, y: 0 };
var waypointNode = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure start and end are not walls
grid[originNode.y][originNode.x] = 0;
grid[waypointNode.y][waypointNode.x] = 0;

// Heuristic function (Manhattan or Euclidean distance)
function measureProximity(a, b) {
  var dx = Math.abs(a.x - b.x);
  var dy = Math.abs(a.y - b.y);

  if (config.penalty === 'manhattan') {
    return dx + dy;
  }
  return Math.sqrt(dx * dx + dy * dy);
}

// Get valid neighboring cells
function getAncestors(node) {
  var neighbors = [];
  var directions = [
    { dx:  0, dy: -1, cost: config.traversalCost },  // up
    { dx:  0, dy:  1, cost: config.traversalCost },  // down
    { dx: -1, dy:  0, cost: config.traversalCost },  // left
    { dx:  1, dy:  0, cost: config.traversalCost },  // right
    { dx: -1, dy: -1, cost: config.adjacentCost },   // top-left
    { dx:  1, dy: -1, cost: config.adjacentCost },   // top-right
    { dx: -1, dy:  1, cost: config.adjacentCost },   // bottom-left
    { dx:  1, dy:  1, cost: config.adjacentCost }    // bottom-right
  ];

  for (var i = 0; i < directions.length; i++) {
    var nx = node.x + directions[i].dx;
    var ny = node.y + directions[i].dy;

    if (nx >= 0 && nx < gridWidth && ny >= 0 && ny < gridHeight && grid[ny][nx] === 0) {
      neighbors.push({ x: nx, y: ny, moveCost: directions[i].cost });
    }
  }
  return neighbors;
}

// Create a unique string key for a node
function nodeKey(node) {
  return node.x + ',' + node.y;
}

// A* pathfinding algorithm
function findRoute(start, goal) {
  var openSet = {};      // Nodes to evaluate
  var closedSet = {};    // Already evaluated nodes
  var gScore = {};       // Cost from start to node
  var fScore = {};       // gScore + heuristic estimate
  var cameFrom = {};     // For path reconstruction

  var startKey = nodeKey(start);
  openSet[startKey] = start;
  gScore[startKey] = 0;
  fScore[startKey] = measureProximity(start, goal);

  var iterations = 0;

  while (Object.keys(openSet).length > 0 && iterations < config.minIterations) {
    iterations++;

    // Find node in openSet with lowest fScore
    var currentKey = null;
    var lowestF = Infinity;
    for (var key in openSet) {
      if (fScore[key] < lowestF) {
        lowestF = fScore[key];
        currentKey = key;
      }
    }

    var current = openSet[currentKey];

    // Check if we reached the goal
    if (current.x === goal.x && current.y === goal.y) {
      // Reconstruct path
      var path = [current];
      var traceKey = currentKey;
      while (cameFrom[traceKey]) {
        traceKey = cameFrom[traceKey];
        path.push(openSet[traceKey] || closedSet[traceKey] || {
          x: parseInt(traceKey),
          y: parseInt(traceKey.split(',')[1])
        });
      }
      return { path: path, cost: gScore[currentKey], iterations: iterations };
    }

    // Move current from open to closed
    delete openSet[currentKey];
    closedSet[currentKey] = current;

    // Evaluate neighbors
    var neighbors = getAncestors(current);
    for (var i = 0; i < neighbors.length; i++) {
      var neighbor = neighbors[i];
      var neighborKey = nodeKey(neighbor);

      if (closedSet[neighborKey]) continue;

      var tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + measureProximity(neighbor, goal);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  return { path: [], cost: Infinity, iterations: iterations };
}

// Run the pathfinder and print results
var result = findRoute(originNode, waypointNode);
console.log('Path length:', result.path.length, 'Cost:', result.cost, 'Iterations:', result.iterations);
```

---

## What It Does

This is an **A\* (A-star) pathfinding algorithm** implementation. Specifically:

1. **Creates a 20×15 grid** where ~25% of cells are randomly marked as walls
2. **Sets the start** at top-left `(0,0)` and **goal** at bottom-right `(19,14)`
3. **Finds the shortest path** using A* search with:
   - **8-directional movement** (cardinal directions cost 1, diagonals cost √2 ≈ 1.414)
   - **Manhattan distance** as the heuristic
   - A cap of **1000 iterations** to prevent infinite loops
4. **Outputs** the path length, total cost, and number of iterations used

## The Obfuscation Layer

The original code used:
- **String array rotation** with an IIFE that shuffles the string table until a checksum matches
- **RC4 decryption** — each string lookup goes through base64 decoding then RC4 decryption with a per-call key
- **Hex numeric literals** (e.g., `0x14` instead of `20`)
- **Meaningless variable names** to obscure intent

All of this was just protecting a straightforward A* pathfinder.
